patch:
@@ -0,0 +1,22 @@
+button {
+  background-color: #303030;
+  border: 1px solid white;
+  color: white;
+  cursor: pointer;
+  left: 0;
+  padding: 5px;
+  position: absolute;
+  top: 0;
+  width: 90px;
+  z-index: 999999;
+}
+
+button:hover {
+  background-color: gray;
+  color: white;
+}
+
+.vr-button {
+  top: 20px;
+  left: 30px;
+}

@@ -0,0 +1,46 @@
+<!DOCTYPE html>
+<html>
+  <head>
+    <meta charset="utf-8">
+    <meta name="viewport" content="width=device-width">
+    <link rel="stylesheet" href="https://fonts.googleapis.com/css?family=Montserrat:400,700">
+    <title>vr-markup examples</title>
+    <style>
+      * {
+        margin: 0;
+        padding: 0;
+      }
+      html {
+        font-size: 11px;
+      }
+      body {
+        background: rgb(53,196,232);
+        color: #fff;
+        font: 2rem/1.5 'Montserrat', sans-serif;
+        margin: 0;
+        padding: 3rem;
+      }
+      h1 {
+        margin: 0 0 3rem;
+      }
+      ul {
+        line-height: 1.5;
+        list-style: none;
+      }
+      a {
+        color: #036;
+        display: block;
+        padding: .5rem 0;
+      }
+      a:hover {
+        color: #369;
+      }
+    </style>
+  </head>
+  <body>
+    <h1>vr-markup examples</h1>
+    <ul>
+      <li><a href="controls/">controls</a></li>
+    </ul>
+  </body>
+</html>
